mapper.select:
SELECT rc.id, rc.name, rc.description, rc.is_root, rc.is_enabled, rc.source_type, rc.source_id, rc.create_time, rc.update_time, jsonb_array_length(rc.configuration -> 'nodes') as node_count, CASE WHEN rc.source_type = 'PRODUCT' THEN p.model WHEN rc.source_type = 'DEVICE' THEN d.device_name ELSE NULL END as source_name FROM tb_rule_chain rc LEFT JOIN tb_product p ON rc.source_type = 'PRODUCT' AND rc.source_id = p.id LEFT JOIN tb_device d ON rc.source_type = 'DEVICE' AND rc.source_id = d.id
AND rc.name LIKE CONCAT('%', #{query.name}, '%')
AND rc.source_type = #{query.sourceType}
AND rc.is_enabled = #{query.isEnabled}
ORDER BY rc.update_time DESC
